<script lang="ts" setup>
  import { computed, onMounted, reactive, ref, watch } from 'vue';
  import { useRoute } from 'vue-router';
  import type { Hotel } from '@/quotes/interfaces';
  import InfoHotelComponent from '@/quotes/components/info/InfoHotelComponent.vue';
  import { getHotelById } from '@/quotes/helpers/get-hotel-by-id';
  import useLoader from '@/quotes/composables/useLoader';
  import { LeftCircleOutlined, RightCircleOutlined } from '@ant-design/icons-vue';
  import { useQuote } from '@/quotes/composables/useQuote';
  import { useI18n } from 'vue-i18n';
  import { storeToRefs } from 'pinia';
  import { useLanguagesStore } from '@/stores/global';

  const { t } = useI18n({
    useScope: 'global',
  });

  const languageStore = useLanguagesStore();

  const { page } = useQuote();
  const { showIsLoading, closeIsLoading } = useLoader();
  const route = useRoute();
  const hotelSelected = ref<Hotel>();

  const stars = computed(() => {
    return hotelSelected.value?.stars ? hotelSelected.value?.stars : 1;
  });

  const galeries = computed(() => {
    return hotelSelected.value?.galleries ?? [];
  });

  const amenities = computed(() => {
    return hotelSelected.value?.amenities ?? [];
  });

  const rooms = computed(() => {
    return hotelSelected.value?.rooms ?? [];
  });

  const state = reactive({
    currentRoom: [true, false],
  });

  const toggleDownRoom = (item: any) => {
    state.currentRoom[item] = !state.currentRoom[item];
  };

  const getHotel = async (id: any) => {
    showIsLoading();
    hotelSelected.value = await getHotelById(id, languageStore.currentLanguage);
    closeIsLoading();
  };

  const changePage = (newView: string) => {
    showIsLoading();
    setTimeout(() => {
      page.value = newView;
    }, 500);
    setTimeout(() => {
      closeIsLoading();
    }, 3000);
  };

  const printHtml = () => {
    window.print();
  };

  const { currentLanguage } = storeToRefs(languageStore);

  watch(currentLanguage, async () => {
    await handleUpdateLanguage();
  });

  const handleUpdateLanguage = async () => {
    await getHotel(route.params.id);
  };

  onMounted(async () => {
    await getHotel(route.params.id);
  });
</script>

